import { useEffect, useMemo, useState } from "react";

export default function DataTable({ status, page }) {
  const [rows, setRows] = useState([]);
  const query = useMemo(() => ({ status, page }), [status, page]);

  useEffect(() => {
    fetch(`/api/rows?status=${query.status}&page=${query.page}`)
      .then(r => r.json())
      .then(data => setRows(data.rows));
  }, [query]);

  return (
    <table>
      <tbody>
        {rows.map(row => (
          <tr key={row.id}><td>{row.name}</td><td>{row.status}</td></tr>
        ))}
      </tbody>
    </table>
  );
}

